evaluations.dslRule:
// String.replaceAll with literal → String.replace
$str.replaceAll($literal, $replacement) :: sourceVersionGE(9) && isStringLiteral($literal) && !containsRegexChars($literal)
=> $str.replace($literal, $replacement)
;;

